258	export async function assemblePrompt(
259	  input: PromptAssemblyInput
260	): Promise<PromptAssemblyResult> {
261	  const assets = getEmbeddedPromptAssets();
262	  const basePromptId = basePromptIdForRole(input.role);
263	  const snippetIds = snippetIdsForInput(input);
264	  const values = runtimeValues(input);
265	  const publicInsert =
266	    input.role === "story_implementor"
267	      ? await loadPublicInsert(input.implementationPromptInsertPath)
268	      : input.role === "story_verifier"
269	        ? await loadPublicInsert(input.verifierPromptInsertPath)
270	        : {};
271	
272	  const sections = [
273	    interpolateTemplate(assets.base[basePromptId], values),
274	    ...snippetIds.map((snippetId) =>
275	      interpolateTemplate(assets.snippets[snippetId], values)
276	    ),
277	    selfReviewSection(input),
278	    publicInsert.content ? publicInsert.content.trimEnd() : "",
279	  ].filter((section) => section.length > 0);
280	
281	  return {
282	    prompt: `${sections.join("\n\n")}\n`,
283	    basePromptId,
284	    snippetIds,
285	    publicInsertIds: publicInsert.assetId ? [publicInsert.assetId] : [],
286	  };
287	}

