 97	  meta: {
 98	    name: "preflight",
 99	    description:
100	      "Validate run config, verification gates, and provider availability.",
101	  },
102	  args: {
103	    "spec-pack-root": {
104	      type: "string",
105	      description: "Absolute or relative path to the spec-pack root",
106	      required: true,
107	    },
108	    config: {
109	      type: "string",
110	      description: "Explicit run-config file relative to the spec-pack root",
111	    },
112	    "story-gate": {
113	      type: "string",
114	      description: "Explicit story verification gate command",
115	    },
116	    "epic-gate": {
117	      type: "string",
118	      description: "Explicit epic verification gate command",
119	    },
120	    json: {
121	      type: "boolean",
122	      description: "Emit the structured JSON envelope on stdout",
123	    },
124	  },
125	  async run({ args }) {
126	    const startedAt = new Date().toISOString();
127	
128	    try {
129	      const inspectResult = await inspectSpecPack(args["spec-pack-root"]);
130	      const artifactPath = await nextArtifactPath(
131	        inspectResult.specPackRoot,
132	        "preflight"
133	      );
134	
135	      if (inspectResult.status !== "ready") {
136	        const envelope: OutputEnvelope = createResultEnvelope({
137	          command: "preflight",
138	          outcome: inspectResult.status,
139	          errors: [
140	            {
141	              code: "INVALID_SPEC_PACK",
142	              message:
143	                inspectResult.status === "blocked"
144	                  ? "Spec-pack inspection failed"
145	                  : "Spec-pack inspection requires a user decision",
146	              detail:
147	                inspectResult.blockers.join("; ") || inspectResult.notes.join("; "),
148	            },
149	          ],
150	          artifacts: [
151	            {
152	              kind: "result-envelope",
153	              path: artifactPath,
154	            },
155	          ],
156	          startedAt,
157	          finishedAt: new Date().toISOString(),
158	        });
159	
160	        await writeJsonArtifact(artifactPath, envelope);
161	        emitOutput({
162	          envelope,
163	          json: Boolean(args.json),
164	        });
165	        process.exitCode = exitCodeForStatus(envelope.status);
166	        return;
167	      }
168	
169	      const validatedConfig = await loadRunConfig({
170	        specPackRoot: inspectResult.specPackRoot,
171	        configPath: args.config,
172	      });
173	      const providerMatrix = await resolveProviderMatrix({
174	        specPackRoot: inspectResult.specPackRoot,
175	        config: validatedConfig,
176	        env: process.env,
177	      });
178	      const gateResolution = await resolveVerificationGates({
179	        specPackRoot: inspectResult.specPackRoot,
180	        explicitStoryGate: args["story-gate"],
181	        explicitEpicGate: args["epic-gate"],
182	      });
183	      const promptAssets = inspectPromptAssets();
184	      const notes = [...inspectResult.notes];
185	
186	      if (
187	        [
188	          validatedConfig.story_implementor,
189	          validatedConfig.quick_fixer,
190	          validatedConfig.story_verifier_1,
191	          validatedConfig.story_verifier_2,
192	          ...validatedConfig.epic_verifiers,
193	          validatedConfig.epic_synthesizer,
194	        ].every((assignment) => assignment.secondary_harness === "none")
195	      ) {
196	        notes.push(
197	          "GPT-capable secondary harnesses are unavailable for this run; the orchestrator should record the Claude-only degraded mode."
198	        );
199	      }
200	
201	      const providerErrors = unavailableProviderErrors(providerMatrix);
202	      const blockers: string[] = [];
203	      const errors: CliError[] = [];
204	      let outcome: "ready" | "needs-user-decision" | "blocked" = "ready";
205	
206	      if (providerErrors.length > 0) {
207	        outcome = "blocked";
208	        errors.push(...providerErrors);
209	        blockers.push(...providerErrors.map((error) => error.message));
210	      } else if (!promptAssets.basePromptsReady || !promptAssets.snippetsReady) {
211	        outcome = "blocked";
212	        errors.push({
213	          code: "PROMPT_ASSET_MISSING",
214	          message: "Embedded prompt assets are incomplete",
215	          detail: promptAssets.notes.join("; "),
216	        });
217	        blockers.push("Embedded prompt assets are incomplete");
218	      } else if (gateResolution.status === "needs-user-decision") {
219	        outcome = "needs-user-decision";
220	        errors.push(...gateResolution.errors);
221	        notes.push(...gateResolution.notes);
222	      }
223	
224	      const preflightResult: PreflightResult = {
225	        status: outcome,
226	        validatedConfig,
227	        providerMatrix,
228	        verificationGates: gateResolution.verificationGates,
229	        configValidationNotes: [],
230	        promptAssets,
231	        blockers,
232	        notes,
233	      };
234	      const envelope = cliResultEnvelopeSchema(preflightResultSchema).parse(
235	        createResultEnvelope({
236	          command: "preflight",
237	          outcome,
238	          result: preflightResult,
239	          errors,
240	          artifacts: [

240	          artifacts: [
241	            {
242	              kind: "result-envelope",
243	              path: artifactPath,
244	            },
245	          ],
246	          startedAt,
247	          finishedAt: new Date().toISOString(),
248	        })
249	      );
250	
251	      await writeJsonArtifact(artifactPath, envelope);
252	      emitOutput({
253	        envelope,
254	        json: Boolean(args.json),
255	      });
256	      process.exitCode = exitCodeForStatus(envelope.status);
257	    } catch (error) {
258	      if (
259	        error instanceof ZodError ||
260	        (error instanceof Error &&
261	          (error.message.includes("Cannot parse") ||
262	            error.message.includes("Required config") ||
263	            error.message.includes("JSON")))
264	      ) {
265	        const envelope: OutputEnvelope = createResultEnvelope({
266	          command: "preflight",
267	          outcome: "blocked",
268	          errors: [
269	            {
270	              code: "INVALID_RUN_CONFIG",
271	              message: "Run-config validation failed",
272	              detail: error instanceof Error ? error.message : String(error),
273	            },
274	          ],
275	          startedAt,
276	          finishedAt: new Date().toISOString(),
277	        });
278	
279	        emitOutput({
280	          envelope,
281	          json: Boolean(args.json),
282	        });
283	        process.exitCode = exitCodeForStatus(envelope.status);
284	        return;
285	      }
286	
287	      const envelope: OutputEnvelope = createResultEnvelope({
288	        command: "preflight",
289	        outcome: "error",
290	        errors: [
291	          {
292	            code: "UNEXPECTED_ERROR",
293	            message: error instanceof Error ? error.message : String(error),
294	          },
295	        ],
296	        startedAt,
297	        finishedAt: new Date().toISOString(),
298	      });
299	
300	      emitOutput({
301	        envelope,
302	        json: Boolean(args.json),
303	      });
304	      process.exitCode = exitCodeForStatus(envelope.status);
305	    }
306	  },
307	});

