110	/**
111	 * Strip YAML frontmatter from composed content for standalone output.
112	 */
113	function stripFrontmatter(content: string): string {
114	  const fmRegex = /^---\n[\s\S]*?\n---\n*/;
115	  return content.replace(fmRegex, "").trimStart();
116	}
